INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('df941fe9-b3e3-5598-b20a-e05e33b39f6a', 'math-6eme', 'جمع وطرح الأعداد الكسرية', 'جمعُ وطرحُ كسرين لهما المقامُ نفسُه، التوحيدُ قبل الجمع/الطرح عند اختلاف المقامات، العمليّاتُ بين كسرٍ وعددٍ صحيح، واختزالُ النتيجة', '# ➕➖ جمعُ الأعداد الكسرية وطرحُها

> 💡 «لجمع كسرين أو طرحهما، يجب أوّلًا أن يكون لهما المقامُ نفسُه.»

## 1️⃣ مقامٌ مشترك

إذا كان للكسرين **المقامُ نفسُه**، نجمع (أو نطرح) **البُسُط** ونُبقي المقامَ كما هو.

- _مثال:_ 2/7 + 3/7 = (2 + 3)/7 = 5/7.
- _مثال:_ 5/8 − 2/8 = (5 − 2)/8 = 3/8.

## 2️⃣ مقاماتٌ مختلفة: نوحّد أوّلًا

نكتب الكسرين بمقامٍ مشترك (مضاعفٌ مشترك للمقامين)، ثمّ نجمع أو نطرح البُسُط.

- _مثال:_ 1/2 + 1/3 ⟸ نوحّد على 6: 3/6 + 2/6 = 5/6.
- _مثال:_ 3/4 − 1/2 ⟸ نوحّد على 4: 3/4 − 2/4 = 1/4.

## 3️⃣ كسرٌ مع عددٍ صحيح

نكتب العددَ الصحيح في صورة كسرٍ بالمقام نفسِه، ثمّ نجمع أو نطرح.

- _مثال:_ 1 + 1/4 = 4/4 + 1/4 = 5/4.
- _مثال:_ 2 − 1/3 = 6/3 − 1/3 = 5/3.

## ✂️ اختزالُ النتيجة

إذا أمكن اختزالُ الكسر الناتج، نكتبه بأبسط صورة.

- _مثال:_ 2/6 + 1/6 = 3/6 = 1/2.

> ⚠️ الفخّ الشائع: جمعُ المقامات أيضًا (مثل كتابة 1/2 + 1/3 = 2/5)؛ المقامُ لا يُجمع، بل نوحّده ونجمع البُسُط فقط.

> 🏆 أتممتَ رحلةَ الكسور: المعنى، التساوي والاختزال، المقارنة، والجمع والطرح. أنت بطلٌ في عالَم الأعداد الكسرية!', '# 📜 ملخّص: جمع وطرح الأعداد الكسرية

- **مقامٌ مشترك:** نجمع/نطرح البُسُط ونُبقي المقام (2/7 + 3/7 = 5/7).
- **مقاماتٌ مختلفة:** نوحّد على مضاعفٍ مشترك، ثمّ نجمع/نطرح البُسُط (1/2 + 1/3 = 3/6 + 2/6 = 5/6).
- **كسرٌ مع عددٍ صحيح:** نكتب الصحيحَ كسرًا بالمقام نفسِه (1 + 1/4 = 4/4 + 1/4 = 5/4).
- **اختزالُ النتيجة** إن أمكن (2/6 + 1/6 = 3/6 = 1/2).
- ⚠️ لا نجمع المقامات؛ المقامُ يبقى (بعد التوحيد) ونجمع البُسُط فقط.', 11, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
