INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('b74ec658-cff2-5483-8314-0189bed02dc9', 'math-6eme', 'الأعداد الكسرية العشرية', 'الكسورُ ذات المقام 10 و100 و1000، الانتقالُ بين الكسر العشريّ والعدد العشريّ، اختزالُ الكسور العشرية، وتحويلُ كسرٍ إلى كسرٍ عشريّ', '# 🔟 الأعداد الكسرية العشرية

> 💡 «الكسرُ العشريّ جسرٌ بين الكسور والأعداد العشرية: 3/10 = 0,3.»

## 🎯 ما هو الكسر العشري؟

الكسرُ العشريّ هو كسرٌ مقامُه **10 أو 100 أو 1000…** (قوّةٌ للعدد 10).

- 3/10, 7/100, 125/1000 كسورٌ عشرية.

## 🔄 من الكسر العشري إلى العدد العشري

عددُ أصفار المقام = عددُ الأرقام بعد الفاصلة:

- 3/10 = 0,3 ؛ 7/100 = 0,07 ؛ 25/100 = 0,25 ؛ 125/1000 = 0,125.

## 🔁 من العدد العشري إلى الكسر العشري

- 0,4 = 4/10 ؛ 0,09 = 9/100 ؛ 1,25 = 125/100.

## ✂️ اختزالُ الكسر العشري

كثيرٌ من الكسور العشرية تُختزل إلى كسورٍ أبسط:

- 5/10 = 1/2 ؛ 25/100 = 1/4 ؛ 8/10 = 4/5.

## ➡️ تحويلُ كسرٍ إلى كسرٍ عشريّ

إذا أمكن جعلُ المقام 10 أو 100… بالضرب، نحصل على القيمة العشرية بسهولة:

- 1/2 = 5/10 = 0,5 ؛ 3/4 = 75/100 = 0,75 ؛ 7/20 = 35/100 = 0,35.

> ⚠️ الفخّ الشائع: الخلطُ بين عدد أصفار المقام وعدد الأرقام بعد الفاصلة (7/100 = 0,07 وليس 0,7).

> 🏆 صرتَ تنتقل بين الكسور والأعداد العشرية بسهولة. التالي: ضربُ عددٍ كسريّ في عددٍ صحيح.', '# 📜 ملخّص: الأعداد الكسرية العشرية

- **كسرٌ عشريّ:** مقامُه 10 أو 100 أو 1000…
- **إلى عدد عشري:** عددُ أصفار المقام = عددُ الأرقام بعد الفاصلة (3/10 = 0,3 ; 7/100 = 0,07).
- **إلى كسر عشري:** 0,4 = 4/10، 1,25 = 125/100.
- **الاختزال:** 5/10 = 1/2، 25/100 = 1/4.
- **تحويلُ كسرٍ:** اجعل المقام 10/100 بالضرب (3/4 = 75/100 = 0,75).', 12, NULL)
