INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('1bbebf9f-703c-5deb-9e06-242993030833', 'math-6eme', 'التناسب والنسبة المئوية', 'وضعيّاتُ التناسب ومعاملُ التناسب، النسبةُ المئوية ككسرٍ مقامُه 100، حسابُ نسبةٍ مئوية من عدد، النِّسَبُ المفيدة، والتحويلُ بين كسرٍ ونسبةٍ مئوية', '# 📊 التناسبُ والنسبةُ المئوية

> 💡 «إذا تضاعفت الكميةُ تضاعف الثمن: هذا هو التناسب.»

## ⚖️ وضعيّةُ تناسب

في وضعيّة تناسب، ننتقل من سطرٍ إلى آخر بالضرب في **العدد نفسِه** يُسمّى **معامل التناسب**.

- _مثال:_ إذا كان ثمنُ 3 أقلامٍ 6 دنانير، فإنّ ثمنَ القلم الواحد = 6 ÷ 3 = 2 دنانير (معامل التناسب 2)؛ ومنه ثمنُ 5 أقلامٍ = 5 × 2 = 10 دنانير.

| عددُ الأقلام | 1   | 3   | 5   |
| ------------ | --- | --- | --- |
| الثمن (د)    | 2   | 6   | 10  |

## 💯 النسبةُ المئوية

النسبةُ المئوية نسبةٌ مقامُها **100**: 25% = 25/100 = 1/4.

- لحساب نسبةٍ مئوية من عدد: نضرب العددَ في النسبة مقسومةً على 100.
- _مثال:_ 20% من 50 = (20/100) × 50 = 10.

## 🧮 نِسَبٌ مفيدة

- 50% = النصف (÷ 2) ؛ 25% = الرُبع (÷ 4) ؛ 10% = العُشر (÷ 10) ؛ 100% = الكلّ.
- _مثال:_ 75% من 80 = ثلاثةُ أرباع = (80 ÷ 4) × 3 = 60.

## 🔄 من كسرٍ إلى نسبةٍ مئوية

نكتب الكسرَ بمقامٍ 100: 15/20 = 75/100 = 75%.

> ⚠️ الفخّ الشائع: نسيانُ القسمة على 100 (20% من 50 ليست 20 × 50 = 1000).

> 🏆 صرتَ توظّف التناسبَ وتحسب النِّسَبَ المئوية. التالي: تطبيقُ التناسب على السرعة والمسافة والزمن.', '# 📜 ملخّص: التناسب والنسبة المئوية

- **التناسب:** ننتقل بين الكميات بالضرب في معامل التناسب (3 أقلام = 6 د ⟹ القلم = 2 د ⟹ 5 أقلام = 10 د).
- **النسبة المئوية:** نسبةٌ مقامُها 100: 25% = 25/100 = 1/4.
- **نسبةٌ من عدد:** العدد × (النسبة ÷ 100) — 20% من 50 = 10.
- **نِسَبٌ مفيدة:** 50% = النصف، 25% = الرُبع، 10% = العُشر، 100% = الكلّ.
- **من كسرٍ إلى %:** اجعل المقام 100 (15/20 = 75/100 = 75%).', 14, NULL)
