  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('38b88a7c-6ff3-5103-9441-29c8c9ea2cbf', 'math-6eme', 'التعامد والتوازي', 'المستقيمان المتعامدان (زاوية قائمة، رمز ⊥) والمتوازيان (رمز ∥)، أدوات الرسم (الكوس والمسطرة)، والخاصّيات الرابطة بين التعامد والتوازي', '# 📐 التعامد والتوازي

> 💡 «خطّان يلتقيان بزاوية قائمة: متعامدان. خطّان لا يلتقيان أبدًا: متوازيان.»

## ⊥ المستقيمان المتعامدان

مستقيمان **متعامدان** إذا تقاطعا وكوّنا **زاوية قائمة** (90°). نكتب: (د1) ⊥ (د2).

- نتحقّق من التعامد ونرسمه بـ**الكوس** (فيه زاوية قائمة).
- في الرسم، نضع **مربّعًا صغيرًا** عند نقطة التقاطع للدلالة على الزاوية القائمة.

## ∥ المستقيمان المتوازيان

مستقيمان **متوازيان** إذا لم يتقاطعا مهما امتدّا، ويبقى البعدُ بينهما **ثابتًا**. نكتب: (د1) ∥ (د2).

- نرسم التوازي بـ**المسطرة والكوس** (نُزلق الكوسَ على طول المسطرة).
- في الرسم، نضع **سهمين متماثلين** (إشارتين) على المستقيمين للدلالة على التوازي.
- مثالٌ من الحياة: حافّتا المسطرة متوازيتان، وحوافُّ الكتاب المتجاورة متعامدة.

## 🔗 خاصّيّتان مفيدتان

- إذا كان مستقيمان متعامدَين مع مستقيمٍ ثالثٍ نفسِه، فهما **متوازيان**:
  $$(د1) ⊥ (د) و (د2) ⊥ (د) ⟹ (د1) ∥ (د2)$$
- إذا وازى مستقيمٌ ثانيًا، ووازى الثاني ثالثًا، فالأوّل يوازي الثالث:
  $$(د1) ∥ (د2) و (د2) ∥ (د3) ⟹ (د1) ∥ (د3)$$

> ⚠️ الفخّ الشائع: الظنّ أنّ كلّ مستقيمين متقاطعين متعامدان؛ التقاطعُ وحدَه لا يكفي — يجب أن تكون الزاويةُ **قائمة**.

> 🏆 صرتَ تُميّز التعامدَ والتوازي وترسمهما. التالي: الزوايا وأنواعها.', '# 📜 ملخّص: التعامد والتوازي

- **متعامدان (⊥):** يتقاطعان ويُكوّنان زاوية قائمة (90°)؛ نرسمهما بالكوس، وعلامتُهما مربّعٌ صغير عند التقاطع.
- **متوازيان (∥):** لا يتقاطعان مهما امتدّا، والبعدُ بينهما ثابت؛ نرسمهما بالمسطرة والكوس، وعلامتُهما سهمان متماثلان.
- **خاصّيات:** (د1) ⊥ (د) و (د2) ⊥ (د) ⟸ (د1) ∥ (د2)؛ و (د1) ∥ (د2) و (د2) ∥ (د3) ⟸ (د1) ∥ (د3).
- ⚠️ التقاطعُ وحدَه لا يعني التعامد؛ يجب زاويةٌ قائمة.', 16, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
