INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('f70cd6cd-a34b-50c7-9f4e-9ab952de929e', 'math-6eme', 'المثلّثات', 'عناصرُ المثلّث (أضلاع، رؤوس، زوايا)، التصنيفُ حسب الأضلاع (متساوي الأضلاع/الساقين/مختلف) وحسب الزوايا (قائم/حادّ/منفرج)، وبناءُ المثلّث', '# 🔺 المثلّثات

> 💡 «ثلاثةُ أضلاع، ثلاثةُ رؤوس، ثلاثُ زوايا: هذا هو المثلّث.»

## 🧩 عناصرُ المثلّث

المثلّثُ مضلّعٌ له **3 أضلاع** و**3 رؤوس** و**3 زوايا**.

## 📏 التصنيفُ حسب الأضلاع

- **متساوي الأضلاع:** أضلاعُه الثلاثة متساوية.
- **متساوي الساقين:** له ضلعان متساويان.
- **مختلف الأضلاع:** أضلاعُه الثلاثة مختلفة الأطوال.

## 📐 التصنيفُ حسب الزوايا

- **قائمُ الزاوية:** فيه زاويةٌ قائمة (90°)، نعلّمها بمربّعٍ صغير.
- **حادُّ الزوايا:** كلُّ زواياه حادّة.
- **منفرجُ الزاوية:** فيه زاويةٌ منفرجة.

## 🛠️ بناءُ مثلّث

نبني مثلّثًا إذا عرفنا **أقيسةَ أضلاعه الثلاثة** (بالمسطرة والفرجار)، أو **ضلعين والزاويةَ المحصورةَ بينهما** (بالمسطرة والمنقلة).

> ⚠️ الفخّ الشائع: الخلطُ بين التصنيف حسب **الأضلاع** (متساوي الأضلاع/الساقين/مختلف) والتصنيف حسب **الزوايا** (قائم/حادّ/منفرج)؛ هما تصنيفان مختلفان لا يُغني أحدُهما عن الآخر.

> 🏆 صرتَ تُصنّف المثلّثات وتعرف كيف تُبنى. التالي: الرباعيّات (المستطيل، المربّع، متوازي الأضلاع، شبه المنحرف).', '# 📜 ملخّص: المثلّثات

- **العناصر:** 3 أضلاع، 3 رؤوس، 3 زوايا.
- **حسب الأضلاع:** متساوي الأضلاع (3 متساوية)، متساوي الساقين (ضلعان متساويان)، مختلف الأضلاع (لا تساوي).
- **حسب الزوايا:** قائم الزاوية (زاوية 90°)، حادّ الزوايا، منفرج الزاوية.
- **البناء:** من أقيسة الأضلاع الثلاثة (مسطرة + فرجار)، أو ضلعين والزاوية بينهما (مسطرة + منقلة).
- **المحيط:** مجموعُ أطوال الأضلاع الثلاثة.
- ⚠️ التصنيفُ حسب الأضلاع غيرُ التصنيف حسب الزوايا.', 18, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('2d9d1d1d-b4a1-54a5-a43f-12946b9464bc', 'math-6eme', 'الرباعيّات', 'متوازي الأضلاع والمستطيل والمعيّن والمربّع وشبه المنحرف، خاصّياتُها (التوازي، الزوايا القائمة، تساوي الأضلاع)، وعلاماتُ الرسم', '# 🔷 الرباعيّات

> 💡 «أربعةُ أضلاع، لكنّ لكلّ رباعيٍّ شخصيّتَه: التوازي والتعامد وتساوي الأضلاع تُميّزها.»

## 📦 الرباعيّاتُ الخاصّة وخاصّياتُها

| الرباعيّ       | الخاصّيات                                            |
| -------------- | ---------------------------------------------------- |
| متوازي الأضلاع | كلُّ ضلعين متقابلين متوازيان ومتساويان               |
| المستطيل       | متوازي أضلاعٍ زواياه الأربعة قائمة (90°)             |
| المعيّن        | متوازي أضلاعٍ أضلاعُه الأربعة متساوية                |
| المربّع        | مستطيلٌ ومعيّنٌ معًا: 4 أضلاع متساوية و4 زوايا قائمة |
| شبه المنحرف    | له **زوجٌ واحد** فقط من الأضلاع المتوازية            |

## 🏷️ علاماتُ الرسم

- **الأضلاع المتوازية:** أسهمٌ متماثلة على الضلعين المتوازيين.
- **الزاوية القائمة:** مربّعٌ صغير في الزاوية.

## 🛠️ بناءُ متوازي الأضلاع

نرسمه بالمسطرة والكوس معتمدين على **توازي الأضلاع المتقابلة وتساويها**.

> ⚠️ الفخّ الشائع: اعتبارُ شبه المنحرف متوازيَ أضلاع؛ شبه المنحرف له **زوجٌ واحد** فقط من الأضلاع المتوازية، بينما متوازي الأضلاع له **زوجان**.

> 🏆 صرتَ تُميّز الرباعيّات بخاصّياتها. أنت الآن جاهزٌ لعالَم القيس: المحيطات والمساحات.', '# 📜 ملخّص: الرباعيّات

- **متوازي الأضلاع:** زوجان من الأضلاع المتوازية والمتساوية.
- **المستطيل:** متوازي أضلاعٍ بزوايا قائمة.
- **المعيّن:** متوازي أضلاعٍ بأربعة أضلاع متساوية.
- **المربّع:** مستطيلٌ + معيّن (4 أضلاع متساوية و4 زوايا قائمة).
- **شبه المنحرف:** زوجٌ واحدٌ فقط من الأضلاع المتوازية.
- **العلامات:** أسهمٌ للتوازي، مربّعٌ صغير للزاوية القائمة.
- ⚠️ شبه المنحرف ليس متوازيَ أضلاع (زوجٌ واحدٌ فقط من التوازي).', 19, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('011bb676-086a-57fa-b3a6-04c5c96d5c4c', 'math-6eme', 'مساحاتُ المضلّعات', 'وحداتُ قيس المساحة وتحويلاتُها، ومساحاتُ المستطيل والمربّع والمثلّث ومتوازي الأضلاع وشبه المنحرف', '# 📐 مساحاتُ المضلّعات

> 💡 «المساحةُ تقيسُ المكانَ الذي يشغلُه سطحٌ مستوٍ. لكلّ مضلّعٍ صيغتُه، والفكرةُ واحدة: كم مربّعَ وحدةٍ يملأُ السطح؟»

## 📏 وحداتُ قيس المساحة

الوحدةُ المرجعيّة هي **المتر المربّع (م²)**: مساحةُ مربّعٍ طولُ ضلعه متر واحد.

| الوحدة             | الرمز | بالنسبة إلى م² |
| ------------------ | ----- | -------------- |
| الكيلومتر المربّع  | كم²   | 1 000 000 م²   |
| الهكتار            | هكتار | 10 000 م²      |
| الآر               | آر    | 100 م²         |
| المتر المربّع      | م²    | 1 م²           |
| الدّيسيمتر المربّع | دسم²  | 0,01 م²        |
| الصّنتيمتر المربّع | سم²   | 0,0001 م²      |

> 🔑 بين كلّ وحدتين متتاليتين للمساحة **عاملُ 100** (لا 10 كما في الأطوال): 1 م² = 100 دسم² = 10 000 سم². والآر والهكتار لقياس مساحات الأراضي.

## 🧮 صِيَغُ المساحات

| المضلّع        | المساحة                                          |
| -------------- | ------------------------------------------------ |
| المستطيل       | الطول × العرض                                    |
| المربّع        | الضلع × الضلع                                    |
| المثلّث        | (القاعدة × الارتفاع) ÷ 2                         |
| متوازي الأضلاع | القاعدة × الارتفاع                               |
| شبه المنحرف    | (القاعدة الكبرى + القاعدة الصغرى) × الارتفاع ÷ 2 |

## 📐 الارتفاع

**الارتفاعُ** قطعةٌ مستقيمةٌ **عموديّةٌ** على القاعدة تصلُ بينها وبين الرأس (أو الضلع) المقابل. نرسمُه متقطّعًا ونضعُ مربّعًا صغيرًا عند قدمه يدلّ على التعامد.

## 🧩 الأشكالُ المركّبة

لحساب مساحة شكلٍ مركّبٍ، نُفكّكُه إلى أشكالٍ بسيطةٍ نعرفُ مساحتَها، ثمّ **نجمعُ** (أو نطرحُ) المساحات.

> ⚠️ الفخّ الشائع: استعمالُ طول الضلع المائل بدلَ **الارتفاع** في مساحة المثلّث أو متوازي الأضلاع. الارتفاعُ دائمًا **عموديٌّ** على القاعدة، وقد يكون خارجَ الشكل.

> 🏆 صرتَ تحسبُ مساحةَ أيّ مضلّعٍ وتُحوّلُ بين وحدات المساحة. التالي: الدائرةُ والقرص.', '# 📜 ملخّص: مساحاتُ المضلّعات

- **الوحدةُ المرجعيّة:** المتر المربّع (م²).
- **بين وحدتين متتاليتين عاملُ 100:** 1 م² = 100 دسم² = 10 000 سم².
- **الآر** = 100 م² · **الهكتار** = 10 000 م² (= 100 آر).
- **المستطيل:** الطول × العرض.
- **المربّع:** الضلع × الضلع.
- **المثلّث:** (القاعدة × الارتفاع) ÷ 2.
- **متوازي الأضلاع:** القاعدة × الارتفاع.
- **شبه المنحرف:** (القاعدة الكبرى + القاعدة الصغرى) × الارتفاع ÷ 2.
- **الشكلُ المركّب:** نُفكّكُه إلى أشكالٍ بسيطةٍ ونجمعُ مساحاتِها.
- ⚠️ الارتفاعُ عموديٌّ على القاعدة؛ لا تستعمل الضلعَ المائل.', 20, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('06b768d6-90f6-54fe-a4f5-a1d55ca5180b', 'math-6eme', 'الدائرة والقرص', 'عناصرُ الدائرة (المركز، نصف القطر، القطر)، محيطُ الدائرة ومساحةُ القرص باستعمال π ≈ 3,14، والتمييزُ بين الدائرة والقرص', '# ⭕ الدائرة والقرص

> 💡 «الدائرةُ خطٌّ منحنٍ مغلق، كلُّ نقطةٍ منه على البعد نفسِه من المركز. والقرصُ هو الدائرةُ وما بداخلها.»

## 🧭 عناصرُ الدائرة

- **المركز:** النقطةُ التي تبعدُ عنها كلُّ نقاط الدائرة بالبعد نفسِه.
- **نصفُ القطر (ر):** القطعةُ التي تصلُ المركزَ بنقطةٍ من الدائرة.
- **القطر (ق):** القطعةُ المارّةُ بالمركز وطرفاها على الدائرة. ✦ **ق = 2 × ر**.

## 🔄 المحيط ومساحةُ القرص

نستعملُ العددَ الثابتَ **π ≈ 3,14**.

| المقدار       | الصيغة              |
| ------------- | ------------------- |
| محيطُ الدائرة | 2 × π × ر (= π × ق) |
| مساحةُ القرص  | π × ر × ر           |

> 🔢 مثال: دائرةٌ نصفُ قطرها 5 سم ⟵ محيطُها = 2 × 3,14 × 5 = 31,4 سم، ومساحةُ قرصها = 3,14 × 5 × 5 = 78,5 سم².

## 🆚 الدائرة أم القرص؟

- **الدائرة:** الخطُّ المنحني وحدَه ⟵ له **محيطٌ** (طول).
- **القرص:** السطحُ الممتلئُ داخلَ الدائرة ⟵ له **مساحةٌ**.

> ⚠️ الفخّ الشائع: الخلطُ بين نصف القطر والقطر في الصيغ. المحيطُ = 2 × π × **نصف القطر**، أو π × **القطر** مباشرةً — اختر صيغةً واحدةً ولا تجمع بينهما.

> 🏆 صرتَ تحسبُ محيطَ الدائرة ومساحةَ القرص. بقيت المُدَدُ الزمنيّةُ لإتمام برنامج القيس.', '# 📜 ملخّص: الدائرة والقرص

- **المركز:** نقطةٌ تبعدُ عنها كلُّ نقاط الدائرة بالبعد نفسِه.
- **نصفُ القطر (ر):** من المركز إلى الدائرة · **القطر (ق) = 2 × ر**.
- **π ≈ 3,14**.
- **محيطُ الدائرة:** 2 × π × ر (= π × ق).
- **مساحةُ القرص:** π × ر × ر.
- **الدائرةُ** خطٌّ له محيطٌ؛ **القرصُ** سطحٌ له مساحةٌ.
- ⚠️ لا تخلط بين نصف القطر والقطر في الصيغ.', 21, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('afb2aa4f-1632-564e-9967-2bf1550865f9', 'math-6eme', 'المُدَدُ الزمنيّة', 'وحداتُ الزمن (الثانية، الدقيقة، الساعة، اليوم...) وعلاقاتُها والتحويلُ بينها، وجمعُ المدد وطرحُها وحسابُ المدّة المنقضية', '# ⏱️ المُدَدُ الزمنيّة

> 💡 «الزمنُ يُقاسُ كغيره، لكنّه لا يَعُدُّ بالعشرات: السّتّونَ (60) هي مفتاحُ الساعات والدقائق والثواني.»

## 🕰️ وحداتُ الزمن وعلاقاتُها

نرمزُ للساعة بـ **سا**، وللدقيقة بـ **د**، وللثانية بـ **ثا**.

| الوحدة      | تساوي                |
| ----------- | -------------------- |
| 1 دقيقة (د) | 60 ثا                |
| 1 ساعة (سا) | 60 د                 |
| 1 ساعة      | 3 600 ثا             |
| 1 يوم       | 24 سا                |
| 1 أسبوع     | 7 أيّام              |
| 1 سنة       | 12 شهرًا (365 يومًا) |

> 🔑 التحويلُ بين الساعة والدقيقة والثانية يكون بـ **60** (لا 10 ولا 100).

## ➕ جمعُ المدد وطرحُها

نجمعُ (أو نطرحُ) الساعاتِ مع الساعات والدقائقَ مع الدقائق. وإذا بلغت الدقائقُ **60** أو أكثر، نحوّلُ كلَّ 60 دقيقة إلى ساعةٍ واحدة.

> 🔢 مثال: 2 سا 40 د + 1 سا 35 د = 3 سا 75 د = **4 سا 15 د** (لأنّ 75 د = 1 سا و15 د).

## ⏳ المدّةُ المنقضية

المدّةُ بين لحظتين = **لحظةُ الوصول − لحظةُ الانطلاق**.

> 🔢 مثال: فيلمٌ انطلق في 14 سا 20 د ودام 1 سا 50 د ⟵ ينتهي في 16 سا 10 د.

> ⚠️ الفخّ الشائع: التعاملُ مع الزمن كعددٍ عشريّ (اعتبارُ الساعة 100 دقيقة). الساعةُ **60 دقيقة**؛ فلا تكتب 1 سا 70 د بل 2 سا 10 د.

> 🏆 أتقنتَ المُدَدَ الزمنيّة. بقيت لمسةٌ أخيرة في القيس: مساحاتُ المُجسّمات (المكعّب ومتوازي المستطيلات).', '# 📜 ملخّص: المُدَدُ الزمنيّة

- **العلاقاتُ الأساسيّة:** 1 د = 60 ثا · 1 سا = 60 د = 3 600 ثا · 1 يوم = 24 سا.
- **1 أسبوع** = 7 أيّام · **1 سنة** = 12 شهرًا (365 يومًا).
- **التحويلُ** بين سا/د/ثا يكون بـ 60 (لا 10 ولا 100).
- **الجمعُ والطرح:** ساعاتٌ مع ساعات ودقائقُ مع دقائق؛ كلُّ 60 دقيقة = 1 ساعة.
- **المدّةُ المنقضية** = لحظةُ الوصول − لحظةُ الانطلاق.
- ⚠️ لا تعامل الزمنَ كعددٍ عشريّ: الساعةُ 60 دقيقة لا 100.', 22, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ac7ad0cb-632a-5f33-99c8-bdd9c9c28dcc', 'math-6eme', 'مساحةُ المكعّب ومتوازي المستطيلات', 'عناصرُ المكعّب ومتوازي المستطيلات (الأوجه، الأحرف، الرؤوس)، وحسابُ المساحة الجانبيّة والمساحة الجمليّة لكلٍّ منهما', '# 🧊 مساحةُ المكعّب ومتوازي المستطيلات

> 💡 «المُجسّمُ له أوجهٌ مستوية. لإيجاد مساحة سطحه نجمعُ مساحاتِ أوجهه، ولكلّ مُجسّمٍ صيغةٌ تختصرُ الطريق.»

## 🧊 المكعّب

للمكعّب **6 أوجهٍ مربّعةٍ متساوية**، و**12 حرفًا**، و**8 رؤوس**. كلُّ أحرفه متساوية، ونسمّي طولَ الحرف ببساطة **الحرف**.

| المساحة   | الصيغة                                           |
| --------- | ------------------------------------------------ |
| الجانبيّة | 4 × (الحرف × الحرف) ← الأوجهُ الأربعةُ الجانبيّة |
| الجمليّة  | 6 × (الحرف × الحرف) ← الأوجهُ الستّةُ كلُّها     |

## 📦 متوازي المستطيلات

له **6 أوجهٍ مستطيلة** (كلُّ وجهين متقابلين متساويان)، و**12 حرفًا**، و**8 رؤوس**، وأبعادُه: الطول والعرض والارتفاع.

| المساحة   | الصيغة                                                           |
| --------- | ---------------------------------------------------------------- |
| الجانبيّة | محيطُ القاعدة × الارتفاع = 2 × (الطول + العرض) × الارتفاع        |
| الجمليّة  | الجانبيّة + 2 × مساحةُ القاعدة = الجانبيّة + 2 × (الطول × العرض) |

> 🔢 مثال: متوازي مستطيلاتٍ طولُه 5 وعرضُه 3 وارتفاعُه 4 ⟵ الجانبيّة = 2 × (5 + 3) × 4 = 64، والجمليّة = 64 + 2 × (5 × 3) = 64 + 30 = 94.

## ✏️ رسمُ المُجسّم

نرسمُ المُجسّمَ في منظورٍ مائل: الأحرفُ المرئيّةُ بخطٍّ متّصل، والأحرفُ المخفيّةُ (خلفَ المُجسّم) بخطٍّ **متقطّع**.

> ⚠️ الفخّ الشائع: الخلطُ بين الجانبيّة والجمليّة. الجانبيّةُ **تُهملُ القاعدتين**، أمّا الجمليّةُ فتضيفُهما (+ 2 × مساحة القاعدة).

> 🏆 بهذا أتممتَ برنامجَ القيس كاملًا، وأكملتَ برنامجَ السنة السادسة في الرياضيات من أوّله إلى آخره. مبروك! 🎉🏅', '# 📜 ملخّص: مساحةُ المكعّب ومتوازي المستطيلات

- **المكعّب:** 6 أوجهٍ مربّعةٍ متساوية، 12 حرفًا، 8 رؤوس.
  - الجانبيّة = 4 × (الحرف × الحرف) · الجمليّة = 6 × (الحرف × الحرف).
- **متوازي المستطيلات:** 6 أوجهٍ مستطيلة، 12 حرفًا، 8 رؤوس.
  - الجانبيّة = محيطُ القاعدة × الارتفاع = 2 × (الطول + العرض) × الارتفاع.
  - الجمليّة = الجانبيّة + 2 × (الطول × العرض).
- في الرسم: الأحرفُ المخفيّةُ تُرسمُ **متقطّعة**.
- ⚠️ الجانبيّةُ بلا قاعدتين؛ الجمليّةُ تضيفُهما.', 23, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

