  ('9f5eebed-a2c1-5c50-b628-c93aebe7b9d3', '018de6a6-7d6c-5307-974a-8d1bc57ec7c3', 'ما المساحةُ الجانبيّة لمتوازي المستطيلات هذا (الطول 6، العرض 3، الارتفاع 4)؟ <svg viewBox="0 0 100 100"><rect x="18" y="50" width="44" height="30" fill="none" stroke="currentColor" stroke-width="2.5"/><polyline points="34,36 78,36 78,66" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="18" y1="50" x2="34" y2="36" stroke="currentColor" stroke-width="2.5"/><line x1="62" y1="50" x2="78" y2="36" stroke="currentColor" stroke-width="2.5"/><line x1="62" y1="80" x2="78" y2="66" stroke="currentColor" stroke-width="2.5"/><line x1="34" y1="36" x2="34" y2="66" stroke="currentColor" stroke-width="1.3" stroke-dasharray="4 3"/><line x1="34" y1="66" x2="78" y2="66" stroke="currentColor" stroke-width="1.3" stroke-dasharray="4 3"/><line x1="18" y1="80" x2="34" y2="66" stroke="currentColor" stroke-width="1.3" stroke-dasharray="4 3"/></svg>', '[{"id":"a","text":"72 سم²"},{"id":"b","text":"36 سم²"},{"id":"c","text":"90 سم²"},{"id":"d","text":"18 سم²"}]'::jsonb, 'a', 'الجانبيّة = محيطُ القاعدة × الارتفاع = 2 × (6 + 3) × 4 = 18 × 4 = 72 سم².', 4, 'mcq', NULL, NULL)
